import os
import sys
import json
import argparse
from urllib.parse import urlparse

import torch
import torch.nn as nn
from torch.utils.data import DataLoader
from torchvision import datasets, transforms, models


def safe_load_state_dict_from_file(path, map_location="cpu"):
    return torch.load(path, map_location=map_location, weights_only=True)


def extract_state_dict(obj):
    if isinstance(obj, dict):
        for key in ("state_dict", "model_state_dict", "model", "net", "module"):
            if key in obj and isinstance(obj[key], dict):
                return obj[key]
    return obj


def infer_num_classes(dataset):
    if hasattr(dataset, "classes"):
        return len(dataset.classes)
    labels = set()
    for _, y in dataset:
        labels.add(int(y))
    return len(labels)


def build_model(name, num_classes, pretrained=True):
    name = name.lower()
    if name == "resnet18":
        weights = models.ResNet18_Weights.DEFAULT if pretrained else None
        model = models.resnet18(weights=weights)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        return model
    if name == "resnet50":
        weights = models.ResNet50_Weights.DEFAULT if pretrained else None
        model = models.resnet50(weights=weights)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        return model
    if name == "mobilenet_v3_small":
        weights = models.MobileNet_V3_Small_Weights.DEFAULT if pretrained else None
        model = models.mobilenet_v3_small(weights=weights)
        in_features = model.classifier[-1].in_features
        model.classifier[-1] = nn.Linear(in_features, num_classes)
        return model
    if name == "efficientnet_b0":
        weights = models.EfficientNet_B0_Weights.DEFAULT if pretrained else None
        model = models.efficientnet_b0(weights=weights)
        in_features = model.classifier[-1].in_features
        model.classifier[-1] = nn.Linear(in_features, num_classes)
        return model
    raise ValueError(f"Unsupported model: {name}")


def freeze_backbone(model):
    for p in model.parameters():
        p.requires_grad = False

    if hasattr(model, "fc"):
        for p in model.fc.parameters():
            p.requires_grad = True
    elif hasattr(model, "classifier"):
        for p in model.classifier.parameters():
            p.requires_grad = True


def download_checkpoint(url, out_dir):
    os.makedirs(out_dir, exist_ok=True)
    filename = os.path.basename(urlparse(url).path) or "checkpoint.pt"
    dst = os.path.join(out_dir, filename)
    torch.hub.download_url_to_file(url, dst)
    return dst


def load_checkpoint_into_model(model, checkpoint_path, device):
    obj = safe_load_state_dict_from_file(checkpoint_path, map_location=device)
    state = extract_state_dict(obj)

    cleaned = {}
    for k, v in state.items():
        nk = k[7:] if k.startswith("module.") else k
        cleaned[nk] = v

    model_state = model.state_dict()
    compatible = {
        k: v for k, v in cleaned.items()
        if k in model_state and model_state[k].shape == v.shape
    }
    missing, unexpected = model.load_state_dict(compatible, strict=False)
    return {"loaded_keys": len(compatible), "missing": missing, "unexpected": unexpected}


def get_dataloaders(data_dir, image_size=224, batch_size=32, workers=4):
    train_tf = transforms.Compose([
        transforms.Resize((image_size, image_size)),
        transforms.RandomHorizontalFlip(),
        transforms.ToTensor(),
    ])
    val_tf = transforms.Compose([
        transforms.Resize((image_size, image_size)),
        transforms.ToTensor(),
    ])

    train_dir = os.path.join(data_dir, "train")
    val_dir = os.path.join(data_dir, "val")

    train_ds = datasets.ImageFolder(train_dir, transform=train_tf)
    val_ds = datasets.ImageFolder(val_dir, transform=val_tf)

    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True, num_workers=workers)
    val_loader = DataLoader(val_ds, batch_size=batch_size, shuffle=False, num_workers=workers)
    return train_ds, val_ds, train_loader, val_loader


def evaluate(model, loader, device):
    model.eval()
    correct = 0
    total = 0
    loss_sum = 0.0
    criterion = nn.CrossEntropyLoss()
    with torch.no_grad():
        for x, y in loader:
            x = x.to(device)
            y = y.to(device)
            logits = model(x)
            loss = criterion(logits, y)
            loss_sum += loss.item() * x.size(0)
            preds = logits.argmax(dim=1)
            correct += (preds == y).sum().item()
            total += y.size(0)
    return loss_sum / max(total, 1), correct / max(total, 1)


def train(model, train_loader, val_loader, device, epochs=5, lr=1e-3):
    criterion = nn.CrossEntropyLoss()
    optimizer = torch.optim.Adam((p for p in model.parameters() if p.requires_grad), lr=lr)

    history = []
    for epoch in range(1, epochs + 1):
        model.train()
        running_loss = 0.0
        seen = 0

        for x, y in train_loader:
            x = x.to(device)
            y = y.to(device)

            optimizer.zero_grad()
            logits = model(x)
            loss = criterion(logits, y)
            loss.backward()
            optimizer.step()

            running_loss += loss.item() * x.size(0)
            seen += x.size(0)

        train_loss = running_loss / max(seen, 1)
        val_loss, val_acc = evaluate(model, val_loader, device)
        history.append({
            "epoch": epoch,
            "train_loss": train_loss,
            "val_loss": val_loss,
            "val_acc": val_acc,
        })
        print(json.dumps(history[-1]))

    return history


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--model", default="resnet18")
    parser.add_argument("--checkpoint-url", required=False, default=None)
    parser.add_argument("--data-dir", required=True)
    parser.add_argument("--output-dir", default="./outputs")
    parser.add_argument("--epochs", type=int, default=5)
    parser.add_argument("--batch-size", type=int, default=32)
    parser.add_argument("--lr", type=float, default=1e-3)
    parser.add_argument("--image-size", type=int, default=224)
    parser.add_argument("--workers", type=int, default=4)
    parser.add_argument("--freeze-backbone", action="store_true")
    args = parser.parse_args()

    os.makedirs(args.output_dir, exist_ok=True)
    device = "cuda" if torch.cuda.is_available() else "cpu"

    train_ds, val_ds, train_loader, val_loader = get_dataloaders(
        args.data_dir,
        image_size=args.image_size,
        batch_size=args.batch_size,
        workers=args.workers,
    )
    num_classes = infer_num_classes(train_ds)

    model = build_model(args.model, num_classes=num_classes, pretrained=True)

    checkpoint_info = None
    if args.checkpoint_url:
        ckpt_path = download_checkpoint(args.checkpoint_url, args.output_dir)
        checkpoint_info = load_checkpoint_into_model(model, ckpt_path, device)

    if args.freeze_backbone:
        freeze_backbone(model)

    model = model.to(device)
    history = train(
        model,
        train_loader,
        val_loader,
        device=device,
        epochs=args.epochs,
        lr=args.lr,
    )

    model_path = os.path.join(args.output_dir, f"{args.model}_finetuned.pt")
    torch.save(
        {
            "model": args.model,
            "num_classes": num_classes,
            "state_dict": model.state_dict(),
            "history": history,
            "checkpoint_info": checkpoint_info,
            "classes": getattr(train_ds, "classes", None),
        },
        model_path,
    )

    print(json.dumps({"saved_model": model_path}))


if __name__ == "__main__":
    main()